export const checkId = 'dynamic-port';
export const name = 'Dynamic Port Configuration';
export const appliesTo = ['deployable', 'server', 'framework'];

const GOOD_PATTERNS = [
  /process\.env\.PORT\b/,
  /process\.env\['PORT'\]/,
  /process\.env\["PORT"\]/,
  /env\.PORT\b/,
  /import\.meta\.env\.PORT\b/,
  /Deno\.env\.get\(['"]PORT['"]\)/,
  /Bun\.env\.PORT\b/,
  /const\s*\{\s*PORT\s*\}\s*=\s*process\.env/,
  /let\s*\{\s*PORT\s*\}\s*=\s*process\.env/,
  /var\s*\{\s*PORT\s*\}\s*=\s*process\.env/,
  /NUXT_PORT\b/,
  /ASTRO_PORT\b/,
  /SERVER_PORT\b/,
  /listen\s*\(\s*(?:process\.env\.PORT|env\.PORT|Deno\.env|Bun\.env|import\.meta\.env\.PORT)/,
];

const BAD_PATTERNS = [
  /\.listen\s*\(\s*(3000|3001|8080|8081|5000|5001|8000|9000|4000|4200)\b/,
  /port\s*:\s*(3000|3001|8080|8081|5000|5001|8000|9000|4000|4200)\b/,
  /['"]port['"]\s*:\s*(3000|3001|8080|8081|5000|5001|8000|9000|4000|4200)\b/,
];

const FALLBACK_PATTERNS = [
  /process\.env\.PORT.*(?:\|\||\?\?)\s*\d+/,
  /(?:Number|parseInt)\s*\(\s*process\.env\.PORT\s*\).*?(?:\|\||\?\?)\s*\d+/,
  /\{\s*PORT\s*=\s*\d+\s*\}\s*=\s*process\.env/,
];

const NON_PROD_PATHS = [
  /(?:^|\/)examples?\//,
  /(?:^|\/)demo\//,
  /(?:^|\/)demos\//,
  /(?:^|\/)test\//,
  /(?:^|\/)__tests__\//,
  /(?:^|\/)spec\//,
  /(?:^|\/)benchmark\//,
  /(?:^|\/)perf\//,
  /(?:^|\/)docs\//,
  /(?:^|\/)fixture\//,
  /(?:^|\/)fixtures\//,
  /(?:^|\/)playground\//,
  /(?:^|\/)sandbox\//,
  /(?:^|\/)stub\//,
  /(?:^|\/)stubs\//,
  /(?:^|\/)mock\//,
  /(?:^|\/)mocks\//,
  /(?:^|\/)e2e\//,
  /(?:^|\/)cypress\//,
  /(?:^|\/)playwright\//,
  /(?:^|\/)storybook\//,
  /(?:^|\/)stories\//,
  /(?:^|\/)coverage\//,
  /\.github\//,
];

function isNonProductionPath(filePath, repoType) {
  if (repoType === 'framework') return false;
  return NON_PROD_PATHS.some(p => p.test(filePath));
}

function isFrameworkRepo(tree, packageJson) {
  const frameworkConfigs = [
    'next.config.js', 'next.config.ts', 'next.config.mjs',
    'nuxt.config.ts', 'nuxt.config.js',
    'astro.config.mjs', 'astro.config.js', 'astro.config.ts',
    'remix.config.js', 'remix.config.ts',
    'svelte.config.js', 'svelte.config.ts',
    'vite.config.ts', 'vite.config.js', 'vite.config.mjs',
    'nitro.config.ts', 'nitro.config.js',
  ];
  if (frameworkConfigs.some(c => tree.includes(c))) return true;

  const deps = { ...packageJson?.dependencies, ...packageJson?.devDependencies };
  const frameworkDeps = ['next', 'nuxt', 'astro', 'remix', '@remix-run/dev', '@sveltejs/kit', 'nitropack', 'nitro'];
  if (frameworkDeps.some(d => deps[d])) return true;

  if (tree.some(p => /^packages\/(astro|nuxt|next|remix|svelte|nitro|vite)\//.test(p))) return true;

  return false;
}

function looksLikeLibraryOrTool(packageJson, tree) {
  if (!packageJson) return false;
  if (isFrameworkRepo(tree, packageJson)) return false;

  const allDeps = { ...packageJson.dependencies, ...packageJson.devDependencies };
  const serverDeps = ['express', 'fastify', 'koa', 'hono', 'nest', 'polka', 'restify', 'connect', 'next', 'nuxt', 'astro', 'remix', '@remix-run/dev', '@sveltejs/kit', 'nitropack', 'nitro'];
  if (serverDeps.some(d => allDeps[d])) return false;

  const scripts = packageJson.scripts || {};
  const serverPatterns = /\b(node|ts-node|nodemon|pm2|serve|http-server|next|nuxt|astro|remix|vite|nitro|wrangler)\b/;
  const serverScriptNames = ['start', 'dev', 'serve', 'preview'];
  for (const name of serverScriptNames) {
    if (scripts[name] && serverPatterns.test(scripts[name])) return false;
  }

  const hasDeployConfig = tree.some(p => /Dockerfile|docker-compose|vercel\.json|netlify\.toml|fly\.toml|render\.yaml|wrangler\.toml/.test(p));
  if (hasDeployConfig) return false;

  const isMonorepo = packageJson.private === true && !!packageJson.workspaces;
  const hasPackages = tree.some(p => /^packages\//.test(p));
  const hasApps = tree.some(p => /^apps\//.test(p));
  if (isMonorepo && hasPackages && !hasApps) {
    if (tree.some(p => /^packages\/(astro|nuxt|next|remix|svelte|nitro|vite)\//.test(p))) return false;
    return true;
  }

  const keywords = packageJson.keywords || [];
  const libKeywords = ['library', 'plugin', 'webpack', 'rollup', 'vite-plugin', 'babel', 'parser', 'compiler', 'build-tool', 'cli', 'toolkit'];
  const hasLibKeyword = keywords.some(k => libKeywords.some(lk => k.toLowerCase().includes(lk)));
  if (packageJson.peerDependencies && hasLibKeyword) return true;

  const mainEntry = packageJson.main || packageJson.module || '';
  if ((mainEntry.includes('dist') || mainEntry.includes('lib') || mainEntry.includes('build')) && !scripts.start) {
    return true;
  }

  if (packageJson.bin && Object.keys(allDeps).length === 0) {
    return true;
  }

  return false;
}

function looksLikeStaticSite(packageJson, tree) {
  const scripts = packageJson?.scripts || {};
  const hasServerScript = scripts.start || scripts.serve || scripts.preview || scripts.dev;
  if (hasServerScript) return false;

  const hasServerFile = tree.some(p => /(^|\/)(server|app|index|main)\.(js|ts|mjs|cjs)$/.test(p) && !/test|spec|\.d\.ts|node_modules|\/dist\/|\/build\//.test(p));
  if (hasServerFile) return false;

  const allDeps = { ...packageJson?.dependencies, ...packageJson?.devDependencies };
  const staticGenerators = ['astro', 'next', 'nuxt', 'gatsby', 'vitepress', 'docusaurus'];
  if (scripts.build && staticGenerators.some(d => allDeps[d])) {
    return true;
  }

  return false;
}

function getFilePriority(filePath) {
  if (/^(apps|packages)\/[^/]+\/(src\/)?(server|app|index|main|entry|start|listen|run|cli|api)\./.test(filePath)) return 1;
  if (/^(apps|packages)\/[^/]+\/(src|lib|api)\//.test(filePath)) return 2;
  if (/^(src|app|server|api|lib|bin)\/(server|app|index|main|entry|start|listen|run|cli|api)\./.test(filePath)) return 3;
  if (/^(src|app|server|api|lib|bin)\//.test(filePath)) return 4;
  if (/^[^/]+\.(js|ts|mjs|cjs)$/.test(filePath)) return 5;
  if (/\.config\.(js|ts|mjs|cjs)$/.test(filePath)) return 6;
  if (/(server|app|index|main|entry|start|listen|run|cli|api|handler|worker)\./.test(filePath)) return 7;
  return 8;
}

function selectRelevantFiles(tree, packageJson) {
  const candidates = new Map();

  if (packageJson?.main) candidates.set(packageJson.main, 0);
  if (packageJson?.bin) {
    if (typeof packageJson.bin === 'string') candidates.set(packageJson.bin, 0);
    else Object.values(packageJson.bin).forEach(v => candidates.set(v, 0));
  }

  const scripts = packageJson?.scripts || {};
  const scriptText = Object.values(scripts).join(' ');
  const refs = scriptText.match(/[\w./@-]+\.(js|ts|mjs|cjs)/g) || [];
  for (const ref of refs) {
    [ref, `src/${ref}`, `app/${ref}`, `bin/${ref}`].forEach(p => {
      if (tree.includes(p)) candidates.set(p, 1);
    });
  }

  for (const p of tree) {
    if (!/\.(js|ts|mjs|cjs)$/.test(p)) continue;
    if (/\.test\.|\.spec\.|__tests__\/|\.d\.ts$|node_modules|\/dist\/|\/build\/|\.output\//.test(p)) continue;

    let priority = getFilePriority(p);
    if (/\/(server|api|listen|serve|gateway|serverless|worker)\//.test(p)) priority -= 1;

    if (!candidates.has(p) || candidates.get(p) > priority) {
      candidates.set(p, priority);
    }
  }

  return Array.from(candidates.entries())
    .filter(([p]) => tree.includes(p))
    .sort((a, b) => a[1] - b[1])
    .slice(0, 15)
    .map(([p]) => p);
}

function analyzeRootScripts(packageJson) {
  const findings = [];
  let dynamic = false;
  let hardcoded = false;
  let framework = false;

  if (!packageJson?.scripts) return { findings, dynamic, hardcoded, framework };

  const frameworkRe = /\b(next\s+(start|dev)|nuxt\s+(start|dev|preview)|astro\s+(dev|preview)|remix-serve|@remix-run\/serve|svelte-kit\s+(dev|preview)|vite\s+preview|nitro\s+(dev|start|preview)|wrangler\s+(dev|publish|pages\s+dev)|serve|http-server)\b/;
  const portRe = /\b(3000|3001|8080|8081|5000|5001|8000|9000|4000|4200)\b/;

  for (const [name, script] of Object.entries(packageJson.scripts)) {
    if (/process\.env\.PORT|\$PORT|\bPORT=/.test(script)) {
      dynamic = true;
      findings.push({ file: 'package.json', issue: `Script "${name}" uses PORT env var: ${script}` });
    }
    if (portRe.test(script)) {
      hardcoded = true;
      findings.push({ file: 'package.json', issue: `Script "${name}" references hardcoded port: ${script}` });
    }
    if (frameworkRe.test(script)) {
      framework = true;
      findings.push({ file: 'package.json', issue: `Script "${name}" uses framework server command: ${script}` });
    }
  }

  return { findings, dynamic, hardcoded, framework };
}

async function analyzeWorkspaceScripts(tree, files) {
  const paths = tree
    .filter(p => p.endsWith('package.json') && !p.includes('node_modules') && p !== 'package.json')
    .filter(p => /^apps\/[^/]+\/package\.json$/.test(p) || /^packages\/[^/]+\/package\.json$/.test(p) || /^[^/]+\/package\.json$/.test(p))
    .slice(0, 3);

  let dynamic = false;
  let hardcoded = false;
  let framework = false;
  const findings = [];
  const frameworkRe = /\b(next\s+(start|dev)|nuxt\s+(start|dev|preview)|astro\s+(dev|preview)|remix-serve|@remix-run\/serve|svelte-kit\s+(dev|preview)|vite\s+preview|serve|http-server)\b/;
  const portRe = /\b(3000|3001|8080|8081|5000|5001|8000|9000|4000|4200)\b/;

  for (const p of paths) {
    let content;
    try {
      content = await files.get(p);
    } catch (e) {
      console.error(`[dynamic-port] Failed to read ${p}:`, e);
      continue;
    }
    if (!content) continue;
    try {
      const pkg = JSON.parse(content);
      const scripts = Object.values(pkg.scripts || {}).join(' ');
      if (/process\.env\.PORT|\$PORT|\bPORT=/.test(scripts)) {
        dynamic = true;
        findings.push({ file: p, issue: 'Workspace package script references PORT env var' });
      }
      if (portRe.test(scripts)) {
        hardcoded = true;
        findings.push({ file: p, issue: 'Workspace package script references hardcoded port' });
      }
      if (frameworkRe.test(scripts)) {
        framework = true;
        findings.push({ file: p, issue: 'Workspace package uses framework server command' });
      }
    } catch {
      // ignore parse errors
    }
  }

  return { dynamic, hardcoded, framework, findings };
}

async function scanFiles(fileList, files, repoType) {
  let foundDynamic = false;
  let foundHardcoded = false;
  let foundFallback = false;
  const findings = [];
  const seen = new Set();

  for (const filePath of fileList) {
    let content;
    try {
      content = await files.get(filePath);
    } catch (e) {
      console.error(`[dynamic-port] Failed to read ${filePath}:`, e);
      continue;
    }
    if (!content) continue;

    const lines = content.split('\n');
    const isNonProd = isNonProductionPath(filePath, repoType);

    for (let i = 0; i < lines.length; i++) {
      const line = lines[i];
      const trimmed = line.trim();
      if (trimmed.startsWith('//') || trimmed.startsWith('/*')) continue;

      for (const pattern of GOOD_PATTERNS) {
        if (pattern.test(line)) {
          foundDynamic = true;
          const key = `${filePath}:${i + 1}:good`;
          if (!seen.has(key)) {
            seen.add(key);
            findings.push({ file: filePath, line: i + 1, issue: 'Uses dynamic port configuration (process.env.PORT or equivalent)' });
          }
        }
      }

      for (const pattern of BAD_PATTERNS) {
        const match = line.match(pattern);
        if (match) {
          const port = match[1] || match[0];
          if (isNonProd) {
            const key = `${filePath}:${i + 1}:nonprod:${port}`;
            if (!seen.has(key)) {
              seen.add(key);
              findings.push({ file: filePath, line: i + 1, issue: `Hardcoded port in non-production code: ${port}` });
            }
          } else {
            foundHardcoded = true;
            const key = `${filePath}:${i + 1}:bad:${port}`;
            if (!seen.has(key)) {
              seen.add(key);
              findings.push({ file: filePath, line: i + 1, issue: `Hardcoded port detected: ${port}` });
            }
          }
        }
      }

      for (const pattern of FALLBACK_PATTERNS) {
        if (pattern.test(line)) {
          if (isNonProd) {
            const key = `${filePath}:${i + 1}:nonprod-fallback`;
            if (!seen.has(key)) {
              seen.add(key);
              findings.push({ file: filePath, line: i + 1, issue: 'Fallback hardcoded port in non-production code' });
            }
          } else {
            foundFallback = true;
            const key = `${filePath}:${i + 1}:fallback`;
            if (!seen.has(key)) {
              seen.add(key);
              findings.push({ file: filePath, line: i + 1, issue: 'Fallback hardcoded port (process.env.PORT || default)' });
            }
          }
        }
      }
    }
  }

  return { foundDynamic, foundHardcoded, foundFallback, findings };
}

export async function check(context) {
  const { tree, files, packageJson, repoType, owner, repo } = context;

  try {
    if (repoType === 'library' || repoType === 'empty') {
      return { checkId, status: 'not-applicable', confidence: 'high', message: 'Library or empty repo — no server port needed', findings: [] };
    }

    if (looksLikeLibraryOrTool(packageJson, tree)) {
      return { checkId, status: 'not-applicable', confidence: 'high', message: 'Library or tool detected — no server port configuration needed', findings: [] };
    }

    if (looksLikeStaticSite(packageJson, tree)) {
      return { checkId, status: 'not-applicable', confidence: 'medium', message: 'Static site detected — no runtime server port needed', findings: [] };
    }

    const relevantFiles = selectRelevantFiles(tree, packageJson);
    const rootScripts = analyzeRootScripts(packageJson);
    const workspaceScripts = await analyzeWorkspaceScripts(tree, files);

    let { foundDynamic, foundHardcoded, foundFallback, findings } = await scanFiles(relevantFiles, files, repoType);

    if (rootScripts.dynamic || workspaceScripts.dynamic) foundDynamic = true;
    if (rootScripts.hardcoded || workspaceScripts.hardcoded) foundHardcoded = true;
    const frameworkServer = rootScripts.framework || workspaceScripts.framework;

    findings = findings.concat(rootScripts.findings, workspaceScripts.findings);

    if (foundHardcoded) {
      if (foundDynamic) {
        return { checkId, status: 'check-it', confidence: 'medium', message: 'Both dynamic and hardcoded port patterns found', findings };
      }
      return { checkId, status: 'fail', confidence: 'high', message: 'Hardcoded port detected — should use process.env.PORT', findings };
    }

    if (foundDynamic) {
      return { checkId, status: 'pass', confidence: 'high', message: 'Dynamic port configuration found (process.env.PORT or equivalent)', findings };
    }

    if (foundFallback) {
      return { checkId, status: 'pass', confidence: 'high', message: 'Dynamic port configuration found with fallback (process.env.PORT || default)', findings };
    }

    if (frameworkServer) {
      return { checkId, status: 'pass', confidence: 'high', message: 'Framework server detected — supports dynamic port via process.env.PORT', findings };
    }

    if (relevantFiles.length > 0) {
      return { checkId, status: 'check-it', confidence: 'medium', message: 'Server files found but no port configuration detected', findings };
    }

    return { checkId, status: 'check-it', confidence: 'low', message: 'No server port configuration found', findings: [] };

  } catch (err) {
    console.error(`[dynamic-port] Error analyzing ${owner}/${repo}:`, err);
    return { checkId, status: 'check-it', confidence: 'low', message: `Analysis error: ${err.message}`, findings: [] };
  }
}
